import{_ as e}from"./chunks/ScaleDisplay.vue_vue_type_script_setup_true_lang.BXLvQvzL.js";import{C as l,o as i,c as n,ag as a,E as o,w as d}from"./chunks/framework.DLbVeA01.js";import"./chunks/Piano.QhCkvqJz.js";const p=JSON.parse('{"title":"和声小调与旋律小调","description":"","frontmatter":{},"headers":[],"relativePath":"scales/harmonic-melodic.md","filePath":"scales/harmonic-melodic.md"}'),s={name:"scales/harmonic-melodic.md"},q=Object.assign(s,{setup(h){return(c,t)=>{const r=l("ClientOnly");return i(),n("div",null,[t[0]||(t[0]=a('<h1 id="和声小调与旋律小调" tabindex="-1">和声小调与旋律小调 <a class="header-anchor" href="#和声小调与旋律小调" aria-label="Permalink to &quot;和声小调与旋律小调&quot;">​</a></h1><p>自然小调有一个&quot;问题&quot;：第 7 音距离主音是<strong>全音</strong>，缺乏&quot;导音&quot;到主音的<strong>半音解决感</strong>。为了解决这个问题，产生了两种变体。</p><h2 id="和声小调-harmonic-minor" tabindex="-1">和声小调 (Harmonic Minor) <a class="header-anchor" href="#和声小调-harmonic-minor" aria-label="Permalink to &quot;和声小调 (Harmonic Minor)&quot;">​</a></h2><p>将自然小调的<strong>第 7 音升高半音</strong>。</p><p>音程模式：W-H-W-W-H-<strong>W½</strong>-H</p><p>以 A 和声小调为例：A-B-C-D-E-F-<strong>G#</strong></p><h3 id="特点" tabindex="-1">特点 <a class="header-anchor" href="#特点" aria-label="Permalink to &quot;特点&quot;">​</a></h3><ul><li>第 6 音和第 7 音之间出现了<strong>增二度</strong>（3 个半音），这是它独特&quot;异域风味&quot;的来源</li><li>第 7 音（G#）变成了真正的&quot;导音&quot;，强烈解决到主音（A）</li><li>常见于：古典音乐、中东音乐、金属乐</li></ul><h2 id="旋律小调-melodic-minor" tabindex="-1">旋律小调 (Melodic Minor) <a class="header-anchor" href="#旋律小调-melodic-minor" aria-label="Permalink to &quot;旋律小调 (Melodic Minor)&quot;">​</a></h2><p>同时升高<strong>第 6 音和第 7 音</strong>，消除增二度的&quot;不自然&quot;感。</p><p>音程模式（上行）：W-H-W-W-<strong>W-W</strong>-H</p><p>以 A 旋律小调为例（上行）：A-B-C-D-E-<strong>F#-G#</strong></p><h3 id="特点-1" tabindex="-1">特点 <a class="header-anchor" href="#特点-1" aria-label="Permalink to &quot;特点&quot;">​</a></h3><ul><li>上行时升高 6、7 音，下行时恢复为自然小调（古典规则）</li><li>在爵士中，上行和下行都使用升高的版本（&quot;爵士旋律小调&quot;）</li><li>常见于：爵士、古典独奏</li></ul>',14)),o(r,null,{default:d(()=>[o(e)]),_:1}),t[1]||(t[1]=a('<h2 id="三种小调对比" tabindex="-1">三种小调对比 <a class="header-anchor" href="#三种小调对比" aria-label="Permalink to &quot;三种小调对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>6 音</th><th>7 音</th><th>特点</th></tr></thead><tbody><tr><td>自然小调</td><td>♭6</td><td>♭7</td><td>最基础，纯粹忧郁</td></tr><tr><td>和声小调</td><td>♭6</td><td>♮7</td><td>异域风味，有导音</td></tr><tr><td>旋律小调</td><td>♮6</td><td>♮7</td><td>接近大调，爵士最爱</td></tr></tbody></table><h2 id="相关主题" tabindex="-1">相关主题 <a class="header-anchor" href="#相关主题" aria-label="Permalink to &quot;相关主题&quot;">​</a></h2><ul><li><a href="/scales/modes.html">教会调式</a> — 更多七声音阶变体</li><li><a href="/scales/blues.html">布鲁斯音阶</a> — 另一种色彩独特的音阶</li></ul>',4))])}}});export{p as __pageData,q as default};
